package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentages;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import com.google.common.collect.ImmutableSet;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY;

@Slf4j
public class LoonCodeCalculatorHasta extends AbstractLoonCodeCalculator {

    private static final Set<LoonElement> EMPTY_SET = ImmutableSet.of();

    public LoonCodeCalculatorHasta(
            SleutelGegevens gegevens, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd,
            LoonCodeCalculatorFactory factory) {
        super(gegevens, aardKodeExtensie, rekenTijd, factory, EMPTY_SET, BigDecimal.ONE);
    }

    @Override
    public Money berekenBedrag100Percent(Money basisBedragIn) {
        log.debug("LoonCodeCalculatorHasta.berekenBedrag100Percent");
        Money basisBedrag = basisBedrag(true);

        log.debug("aardKodeExtensie:{}", aardKodeExtensie);
        Money hasta1 =
                constantManager.getByCodeDatum(aardKodeExtensie.getConst1nr(), TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode)).getMoney();
        Money hasta2 =
                constantManager.getByCodeDatum(aardKodeExtensie.getConst2nr(), TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode)).getMoney();
        Money grens1 =
                constantManager.getByCodeDatum(aardKodeExtensie.getConst3nr(), TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode)).getMoney();
        Money grens2 =
                constantManager.getByCodeDatum(aardKodeExtensie.getConst4nr(), TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode)).getMoney();
        log.debug("basisbedrag:{}; hasta1:{}; hasta2{}; grens1:{}; grens2{}", basisBedrag, hasta1, hasta2, grens1, grens2);
        BigDecimal faktor = BigDecimal.ONE;
        if (RekenTools.isVastbenoemd(gegevens, rekenTijd)) {
            BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
            LocalDate zoekDatum = TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode);
            BigDecimal bijdragePensioenVastbenoemden = bijdragePercentages.bepaal(BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY, gegevens, zoekDatum);
            BigDecimal bijdrageApartePensioenKas = bijdragePercentages.bepaal(BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY, gegevens, zoekDatum);
            faktor = faktor.subtract(bijdragePensioenVastbenoemden).subtract(bijdrageApartePensioenKas);
            faktor = faktor.max(BigDecimal.ZERO);
            log.debug("isVastbenoemd factor:{}", faktor);
        }
        Money hastaGeld;
        if (basisBedrag.compareTo(grens1) <= 0) {
            hastaGeld = hasta1;
            log.debug("basisBedrag<=grens1: hastaGeld = hasta1:{}", hastaGeld);
        } else if (basisBedrag.compareTo(grens2) <= 0) {
            hastaGeld = grens1.multiply(faktor).add(hasta1).subtract(basisBedrag.multiply(faktor));
            hastaGeld = hastaGeld.max(hasta2);
            log.debug("grens1<basisBedrag<=grens2: hastaGeld = max(hasta2,grens1*factor+hasta1-basisbedrag*factor):{}", hastaGeld);
        } else {
            hastaGeld = grens2.multiply(faktor).add(hasta2).subtract(basisBedrag.multiply(faktor));
            hastaGeld = hastaGeld.max(Money.ZERO);
            log.debug("grens2<basisBedrag: hastaGeld = max(ZERO,grens2*factor+hasta2-basisbedrag*factor):{}", hastaGeld);
        }
        hastaGeld = hastaGeld.round(2);

        return hastaGeld;
    }

}
